INSERT INTO policies (title, content) VALUES
('Tiến hành đặt hàng', 'Bước 1 Khách hàng có thể đặt hàng online bằng các hình thức sau đặt tại nút Mua Ngay trên website https://hoanghamobile.com gọi tổng đài 1900.2091 bình luận hoặc chat trên Facebook https://facebook.com/hoanghamobilecom hoặc gửi email đến online@hoanghamobile.com Bước 2 Hoàng Hà Mobile sẽ có nhân viên gọi điện xác nhận đơn hàng Đơn hàng chỉ được coi là thành công khi có nhân viên telesale xác nhận Đơn đặt từ 8h30 đến 16h59 được xác nhận trong ngày sau 17h được xác nhận vào ngày hôm sau'),

('Chính sách đặt hàng và giữ hàng', 'Sau khi đặt hàng đơn hàng được giữ trong 24 giờ kể từ thời điểm đặt và giữ giá khuyến mãi quà tặng nếu có Sau 24 giờ nếu khách không nhận hàng đơn sẽ bị hủy Đơn hàng cuối chương trình khuyến mãi chỉ giữ giá nếu khách nhận trong ngày hoặc thanh toán trước Đơn giờ vàng chỉ áp dụng trong thời gian quy định Trường hợp hết hàng khách có thể thanh toán trước để giữ giá'),

('Các trường hợp hủy đơn hàng', 'Hoàng Hà Mobile có quyền hủy đơn hàng trong các trường hợp sản phẩm hết hàng lỗi giá hoặc thông tin sai do hệ thống thanh toán thất bại hoặc có dấu hiệu gian lận không thể giao hàng hoặc lỗi vận hành Nếu đơn hàng bị hủy toàn bộ số tiền đã thanh toán sẽ được hoàn lại theo phương thức ban đầu'),

('Chi phí giao hàng', 'Đơn hàng dưới 300000 đồng thu phí 20000 đồng Đơn từ 300000 đồng trở lên miễn phí vận chuyển toàn quốc Đối với hàng cồng kềnh sẽ áp dụng phí riêng tùy theo loại sản phẩm và kích thước'),

('Quy định hàng cồng kềnh', 'Hàng cồng kềnh bao gồm các sản phẩm như laptop màn hình tivi điện máy gia dụng hoặc phụ kiện như máy lọc không khí hoặc có khối lượng thực tế lớn hơn 8kg khối lượng quy đổi lớn hơn 10kg theo công thức kích thước hoặc kích thước vượt quá quy định về chiều dài chiều rộng chiều cao Phí áp dụng gồm tivi đến 55 inch là 150000 đồng mỗi sản phẩm màn hình hoặc laptop là 50000 đồng mỗi sản phẩm điều hòa dưới 30km là 150000 đồng từ 30 đến 200km là 250000 đồng trên 200km là 350000 đồng các sản phẩm khác tính theo đơn vị vận chuyển'),

('Hướng dẫn thanh toán', 'Khách hàng có thể thanh toán tại cửa hàng bằng tiền mặt chuyển khoản hoặc quẹt thẻ Đối với đơn online có thể chọn thanh toán khi nhận hàng hoặc thanh toán qua VietQR bằng cách quét mã trên website Lưu ý không áp dụng VietQR cho đơn hàng trên 20 triệu đồng Nếu cần xuất hóa đơn VAT thông tin phải thuộc doanh nghiệp'),

('Thời gian vận chuyển', 'Tại Hà Nội và thành phố Hồ Chí Minh giao trong ngày với khoảng cách dưới 10km hoặc trong 24 giờ với khoảng cách lớn hơn Các tỉnh có cửa hàng giao trong ngày hoặc từ 1 đến 3 ngày Các khu vực khác từ 2 đến 4 ngày tùy địa lý Đơn xác nhận sau 14h30 sẽ tính sang ngày hôm sau Không tính Chủ nhật và ngày lễ'),

('Thời gian hoàn tiền', 'Tiền mặt và chuyển khoản từ 1 đến 3 ngày Thẻ ATM hoặc thẻ quốc tế từ 7 đến 10 ngày Thanh toán qua VietQR hoặc Kredivo từ 1 đến 3 ngày Thanh toán qua ví điện tử từ 7 đến 10 ngày Không tính ngày nghỉ lễ và cuối tuần'),

('Chính sách kiểm hàng và khiếu nại', 'Hoàng Hà Mobile không hỗ trợ đồng kiểm Khách hàng cần quay video khi mở hộp sản phẩm Nếu có lỗi hoặc sai sản phẩm sẽ được hỗ trợ đổi trả Nếu kiện hàng bị móp méo ẩm ướt hoặc mất niêm phong khách có thể từ chối nhận và liên hệ tổng đài 19002091'),

('Chính sách đổi trả sản phẩm', 'Áp dụng đổi mới theo chính sách bảo hành như tại cửa hàng Hoàng Hà Mobile hỗ trợ chi phí vận chuyển nếu sản phẩm lỗi trong 15 ngày Khi gửi bảo hành khách cần thoát tài khoản trên thiết bị và liên hệ tổng đài để được hướng dẫn'),

('Lưu ý chung', 'Khách hàng cần cung cấp thông tin chính xác khi đặt hàng Một số đơn giá trị cao hoặc địa chỉ khó giao sẽ được xác nhận lại Nếu giao hàng chậm mà không báo trước khách có thể từ chối nhận và được hoàn tiền Công ty cam kết sản phẩm chính hãng có hóa đơn và bảo hành Khách cần kiểm tra kỹ trước khi nhận vì sẽ không chịu trách nhiệm sau khi đã ký nhận'),
('Trả góp qua công ty tài chính', 'Hoàng Hà Mobile hỗ trợ trả góp qua các công ty tài chính như Home Credit và FE Credit với ưu đãi trả góp 0 phần trăm cho một số sản phẩm trong thời gian khuyến mãi số lượng có hạn Lãi suất dao động từ 3.5 phần trăm đến 4.5 phần trăm mỗi tháng thời gian vay linh hoạt thời gian thẩm định nhanh thủ tục đơn giản chỉ cần căn cước công dân hoặc chứng minh thư và giấy phép lái xe hỗ trợ nhiều đối tượng khách hàng'),

('Trả góp Shinhan Finance', 'Chương trình trả góp qua Shinhan áp dụng cho các sản phẩm từ 3 triệu trở lên bao gồm iPhone laptop và các sản phẩm khác với kỳ hạn 3 6 8 tháng Ví dụ kỳ hạn 6 tháng với mức lãi suất 0 phần trăm cho sản phẩm trên 25 triệu và từ 10 đến 25 triệu còn sản phẩm từ 3 đến 10 triệu áp dụng lãi suất 0.99 phần trăm mỗi tháng Khách cần trả trước từ 10 phần trăm đến 55 phần trăm tùy giá trị sản phẩm và chịu phí khoản vay từ 2 phần trăm đến 7 phần trăm Quy trình gồm mang giấy tờ cá nhân đến cửa hàng nhân viên tư vấn gói vay công ty tài chính thẩm định hồ sơ và khách ký hợp đồng nhận máy Điều kiện gồm từ 19 đến 70 tuổi có giấy tờ hợp lệ và với khoản vay trên 20 triệu cần thêm chứng minh thu nhập'),

('Trả góp qua Payoo', 'Cổng thanh toán Payoo là nền tảng do VietUnion phát triển hỗ trợ thanh toán điện tử và trả góp qua thẻ tín dụng Khách hàng được hưởng lãi suất 0 phần trăm mỗi tháng và chỉ trả phí chuyển đổi trả góp Payoo hỗ trợ khoảng 27 ngân hàng với kỳ hạn 6 tháng Khách chỉ cần thao tác trên máy Payoo tại cửa hàng không cần nhập thông tin qua link bên ngoài để tránh mất phí Một số ngân hàng có thể thu thêm phí như Techcombank thu khoảng 1.1 phần trăm tối đa 150000 đồng Ngoài ra thẻ VIB có thêm gói lãi suất 1 phần trăm mỗi tháng với kỳ hạn linh hoạt'),

('Trả góp Home PayLater', 'Home PayLater là dịch vụ mua trước trả sau thuộc Home Credit thông qua cổng Bảo Kim cho phép khách hàng mua hàng không cần trả trước và thanh toán sau theo kỳ hạn 1 tháng 3 tháng 6 tháng hoặc 12 tháng Thời gian xét duyệt nhanh từ 30 giây đến 3 phút thủ tục đơn giản chỉ cần căn cước công dân và số điện thoại chính chủ Có thể đăng ký online Mức phí gồm gói 1 tháng miễn phí gói 3 tháng phí 3 phần trăm mỗi tháng gói 6 tháng 3.55 phần trăm mỗi tháng và gói 12 tháng 3.75 phần trăm mỗi tháng Giá trị khoản vay từ vài trăm nghìn đến tối đa 25 triệu tùy kỳ hạn'),

('Samsung Finance Plus', 'Samsung Finance Plus là giải pháp tài chính hỗ trợ mua trả góp sản phẩm Samsung Galaxy với lãi suất 0 phần trăm không cần thẻ tín dụng Duyệt vay nhanh trong khoảng 7 phút thủ tục online chỉ cần căn cước công dân Điều kiện gồm từ 18 đến 60 tuổi thu nhập từ 4 triệu đồng có số điện thoại chính chủ và email Khách có thể trả trước từ 0 đến 50 phần trăm hạn mức tối đa 25 triệu đồng kỳ hạn 12 tháng Khách thanh toán qua ngân hàng thẻ hoặc điểm thanh toán liên kết Hệ thống có nhắc nhở thanh toán và có thể khóa thiết bị nếu chậm thanh toán quá hạn Khách có thể tất toán trước không mất phí'),

('Trả góp Kredivo', 'Kredivo cung cấp dịch vụ trả góp với nhiều ưu đãi cho người dùng mới và cũ như giảm giá trực tiếp hoặc hoàn tiền áp dụng cho đơn từ 700 nghìn đến 10 triệu đồng trở lên với kỳ hạn 3 6 hoặc 12 tháng Kredivo hỗ trợ nhiều hình thức như thanh toán sau 30 ngày 3 tháng hoặc trả góp dài hạn với lãi suất từ 0 đến 2.5 phần trăm mỗi tháng tùy gói Người dùng cơ bản có hạn mức thấp hơn người dùng cao cấp tối đa lên đến 50 triệu đồng Quy trình thanh toán gồm chọn sản phẩm nhập thông tin chọn Kredivo và xác nhận bằng mã PIN qua SMS'),
('Chính sách bảo hành chung', 'Áp dụng từ ngày 29 tháng 09 năm 2025 Hoàng Hà Mobile chân thành cảm ơn quý khách hàng dưới đây là chi tiết chính sách bảo hành áp dụng với tất cả các sản phẩm Hoàng Hà Mobile luôn nỗ lực mang đến chất lượng dịch vụ tốt nhất'),

('Cam kết lỗi đổi liền', 'Hoàng Hà Mobile triển khai chương trình lỗi đổi liền áp dụng toàn hệ thống nhằm mang đến trải nghiệm mua sắm an tâm khách hàng sẽ được đổi mới miễn phí nếu sản phẩm phát sinh lỗi phần cứng hoặc phần mềm do nhà sản xuất áp dụng cho điện thoại máy tính bảng đồng hồ thông minh và các thiết bị đeo thông minh mua mới tại Hoàng Hà'),

('Thời gian đổi sản phẩm', 'Trong 15 hoặc 30 ngày đầu tùy sản phẩm khách hàng được đổi mới miễn phí nếu lỗi do nhà sản xuất thời gian xử lý khoảng 30 phút tại cửa hàng sau thời gian này khách có thể chọn bảo hành chính hãng đổi máy tương đương hoặc tham gia chương trình thu cũ đổi mới'),

('Quy trình đổi lỗi', 'Khách mang sản phẩm cùng hộp và phụ kiện đến cửa hàng nhân viên kiểm tra và xác nhận lỗi nếu không thể khắc phục sẽ đổi máy mới hoặc đề xuất phương án khác sau đó hoàn tất thủ tục và bàn giao máy mới sản phẩm lỗi sẽ được chuyển về trung tâm xử lý'),

('Điều kiện đổi mới', 'Sản phẩm phải lỗi do nhà sản xuất máy còn nguyên vẹn không trầy xước móp méo không vào nước không bị can thiệp phần cứng hoặc phần mềm và có đầy đủ hộp phụ kiện nếu thiếu sẽ trừ phí'),

('Cam kết dịch vụ', 'Thẩm định nhanh minh bạch hỗ trợ đổi máy mới hoặc cho mượn máy trong thời gian chờ bảo hành luôn đặt trải nghiệm khách hàng lên hàng đầu'),

('Lưu ý đổi trả', 'Không áp dụng đổi mới với lỗi do người dùng như rơi vỡ vào nước hoặc can thiệp sửa chữa ngoài hệ thống phụ kiện dưới một triệu đồng sẽ được kiểm tra và đổi ngay nếu đủ điều kiện'),

('Chính sách đổi trả theo sản phẩm', 'Laptop màn hình máy tính bảng điện thoại iPhone MacBook iPad Apple Watch được đổi mới trong 30 ngày trong 30 ngày đầu nếu trả lại sẽ trừ tối thiểu 20 phần trăm giá trị thiếu phụ kiện trừ thêm 5 phần trăm sau 30 ngày nhập lại theo giá thỏa thuận một số sản phẩm như màn hình tivi smart home không hỗ trợ trả lại'),

('Chính sách riêng từng nhóm', 'Tai nghe loa đổi trong 15 ngày AirPods được trả lại trong 15 ngày với phí từ 15 phần trăm điện thoại Oppo Vivo hỗ trợ đổi đến 180 ngày Samsung Watch trừ phí 30 phần trăm khi trả lại phụ kiện chỉ bảo hành không hỗ trợ trả lại'),

('Bảo hành quà tặng', 'Quà tặng là sản phẩm điện tử được đổi trong 15 ngày nếu lỗi sau đó bảo hành theo hãng quà tặng nhỏ không có bảo hành chỉ hỗ trợ đổi trong 15 ngày một số quà tặng như ốp lưng kính cường lực không hỗ trợ bảo hành'),

('Điều kiện đổi trả chung', 'Sản phẩm và hộp còn như mới đầy đủ phụ kiện không móp méo không cong vênh không bị tác động bên ngoài không có dấu hiệu vào nước đã đăng xuất các tài khoản cá nhân màn hình lỗi điểm chết phải đạt tiêu chuẩn theo quy định'),

('Chính sách bảo hành sản phẩm', 'Tất cả sản phẩm đều là hàng chính hãng và được bảo hành theo quy định khách có thể bảo hành tại trung tâm hãng hoặc cửa hàng Hoàng Hà thời gian bảo hành máy mới 12 tháng máy cũ 6 tháng hoặc theo hãng'),

('Nguyên tắc bảo hành', 'Sản phẩm được bảo hành miễn phí nếu còn thời hạn bảo hành tính từ ngày mua khi đổi máy thời hạn bảo hành còn lại được giữ nguyên bảo hành chỉ áp dụng với sản phẩm do Hoàng Hà cung cấp lỗi do nhà sản xuất trong điều kiện sử dụng bình thường'),

('Trường hợp không bảo hành', 'Không bảo hành với các trường hợp hỏng do rơi vỡ va đập cháy nổ sử dụng sai cách ngấm nước can thiệp phần cứng hoặc phần mềm tự ý sửa chữa máy mất số serial hoặc không xác định được nguồn gốc mua tại Hoàng Hà'),

('Lưu ý bảo hành', 'Khách cần sao lưu dữ liệu trước khi bảo hành Hoàng Hà không chịu trách nhiệm mất dữ liệu không chịu trách nhiệm với phụ kiện ngoài máy khách cần đăng xuất tài khoản trước khi bảo hành các trường hợp root jailbreak hoặc cài phần mềm ngoài hệ thống sẽ không được bảo hành'),

('Thời gian tiếp nhận bảo hành', 'Khách có thể mang sản phẩm đến cửa hàng Hoàng Hà theo giờ làm việc hoặc đến trung tâm bảo hành hãng theo thời gian làm việc của hãng'),
('Hướng dẫn sử dụng nền tảng', 'Khi truy cập website khách hàng phải đủ 18 tuổi hoặc có sự giám sát của cha mẹ hoặc người giám hộ hợp pháp khách hàng đảm bảo có đầy đủ năng lực hành vi dân sự để thực hiện giao dịch Hoàng Hà Mobile cấp quyền truy cập nền tảng để đặt hàng theo các điều khoản quy định nghiêm cấm sử dụng nền tảng cho mục đích thương mại hoặc nhân danh bên thứ ba khi chưa được cho phép nếu vi phạm có thể bị thu hồi quyền truy cập mà không cần thông báo trước khách hàng không cần đăng ký tài khoản vẫn có thể đặt hàng'),

('Ý kiến khách hàng', 'Tất cả nội dung hiển thị trên nền tảng bao gồm ý kiến nhận xét của khách hàng đều thuộc sở hữu của Hoàng Hà Mobile nếu phát hiện thông tin giả mạo hoặc vi phạm chúng tôi có quyền xóa nội dung và áp dụng biện pháp theo quy định pháp luật'),

('Đặt hàng và xác nhận đơn hàng', 'Khách hàng có thể đặt hàng qua website hotline 1900.2091 Facebook hoặc email online@hoanghamobile.com sau khi đặt hàng nhân viên sẽ gọi điện xác nhận đơn hàng chỉ được coi là thành công khi có xác nhận từ nhân viên telesale đơn đặt từ 8 giờ 30 đến 16 giờ 59 được xác nhận trong ngày sau 17 giờ xác nhận vào ngày hôm sau đơn hàng được giữ trong 24 giờ kèm giá khuyến mãi nếu có sau thời gian này sẽ bị hủy đơn hàng cuối chương trình khuyến mãi chỉ giữ giá nếu nhận trong ngày hoặc thanh toán trước đơn giờ vàng chỉ áp dụng trong thời gian quy định nếu hết hàng có thể thanh toán trước để giữ giá khách có thể thay đổi địa chỉ giao hàng bằng cách liên hệ sớm Hoàng Hà Mobile có quyền hủy đơn nếu hết hàng lỗi giá thanh toán thất bại hoặc không thể giao hàng và sẽ hoàn tiền nếu đã thanh toán'),

('Hình thức thanh toán', 'Hiện tại Hoàng Hà Mobile hỗ trợ thanh toán tại cửa hàng bằng tiền mặt thẻ tín dụng thẻ ghi nợ hoặc thẻ ATM với đơn online khách có thể chọn thanh toán khi nhận hàng hoặc chuyển khoản trước khuyến khích sử dụng hình thức thanh toán khi nhận hàng'),

('Thời gian vận chuyển', 'Đơn dưới 300000 đồng phí vận chuyển 20000 đồng từ 300000 đồng trở lên miễn phí nội thành Hà Nội và thành phố Hồ Chí Minh giao trong ngày nếu xác nhận trước 14 giờ 30 sau thời gian này giao ngày hôm sau khu vực ngoại thành giao từ 1 đến 2 ngày các tỉnh có cửa hàng giao trong ngày hoặc 2 đến 3 ngày các tỉnh khác từ 3 đến 4 ngày tùy khu vực có thể cần nhận hàng tại sảnh hoặc tầng trệt tùy điều kiện giao nhận không tính Chủ nhật và ngày lễ'),

('Nhận hàng và kiểm tra', 'Khách hàng không được đồng kiểm khi nhận hàng chỉ kiểm tra bên ngoài kiện hàng và mở sau khi thanh toán cần quay video khi mở hộp nếu có lỗi sẽ được hỗ trợ đổi trả sản phẩm được đóng gói niêm phong nếu kiện hàng bị hư hỏng khách có thể từ chối nhận và liên hệ tổng đài nếu phát sinh khiếu nại sẽ được xử lý và hoàn tiền sau khi có kết quả'),

('Giá cả', 'Giá sản phẩm đã bao gồm thuế giá trị gia tăng và có thể thay đổi theo thời điểm và chương trình khuyến mãi phí vận chuyển có thể được miễn phí tùy chính sách'),

('Chính sách đổi trả', 'Hoàng Hà Mobile hỗ trợ chi phí vận chuyển cho các trường hợp lỗi trong 15 ngày khách cần thoát tài khoản trước khi gửi bảo hành thời gian đổi mới tính từ ngày nhận hàng khách liên hệ tổng đài để được hướng dẫn sau khi nhận sản phẩm sẽ có bộ phận tiếp nhận và xử lý trong thời gian sớm nhất chỉ chấp nhận đơn hàng có thông tin chính xác có thể xác nhận lại với đơn giá trị cao nếu giao hàng chậm khách có quyền từ chối nhận và được hoàn tiền Hoàng Hà Mobile cam kết hàng chính hãng khách cần kiểm tra kỹ trước khi nhận vì không chịu trách nhiệm nếu không có video mở hộp'),

('Bảo mật thông tin', 'Hoàng Hà Mobile áp dụng các biện pháp bảo mật để bảo vệ thông tin khách hàng dữ liệu được mã hóa trong quá trình giao dịch chỉ cung cấp thông tin khi có yêu cầu từ cơ quan pháp luật nghiêm cấm can thiệp hệ thống hoặc phát tán dữ liệu vi phạm sẽ bị xử lý theo quy định'),

('Giải quyết tranh chấp', 'Mọi tranh chấp phát sinh sẽ được giải quyết theo quy định của pháp luật Việt Nam toàn bộ điều khoản áp dụng từ ngày 31 tháng 12 năm 2024'),
('Chính sách xuất hóa đơn', 'Cảm ơn khách hàng đã mua sắm tại Hoàng Hà Mobile Quý khách hàng khi mua bất kỳ hàng hóa dịch vụ nào tại hệ thống Hoàng Hà Mobile đều được xuất hóa đơn VAT hóa đơn điện tử ngay tại thời điểm mua hàng theo đúng quy định pháp luật Trường hợp quý khách không nhận được hóa đơn vui lòng liên hệ tổng đài 19002091 để được hỗ trợ xử lý kịp thời'),
('Chăm sóc khách hàng', 'Bộ phận chăm sóc khách hàng là bộ phận chuyên tiếp nhận góp ý thắc mắc và phản hồi của khách hàng trước trong và sau khi mua hàng với đội ngũ nhân viên năng động và sẵn sàng lắng nghe mọi thắc mắc về dịch vụ chất lượng sản phẩm đều được tiếp nhận và tư vấn rõ ràng cụ thể nhằm mang lại trải nghiệm mua hàng trọn vẹn nhất tại Hoàng Hà Mobile khách hàng cần thông tin về sản phẩm chính sách bán hàng hoặc các vấn đề liên quan có thể liên hệ qua email cskh@hoanghamobile.com hotline 1900 2091 hoặc các số điện thoại 0932806326 0912199326 0348044266 0348044450 0348044461 0348044485 0348045586 phòng marketing 0966529192 hoặc để lại tin nhắn qua fanpage Zalo Hoang Ha Facebook Hoanghamobilecom chúng tôi sẽ phản hồi sớm nhất có thể');